import React, { useState, useEffect } from 'react';

export default function InsightSearch() {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [insightOptions, setInsightOptions] = useState([]);

  useEffect(() => {
    // Fetch insight list for dropdown
    fetch('/api/insights')
      .then(res => res.json())
      .then(data => {
        setInsightOptions(data.map(i => i.insightName));
      })
      .catch(err => console.error('Failed to load insights:', err));
  }, []);

  const filterByInsight = async () => {
    try {
      const res = await fetch(`/api/insight/search?q=${encodeURIComponent(query)}`);
      if (!res.ok) throw new Error("Insight not found or server error");
      const data = await res.json();
      setResult(data);
      setError(null);
    } catch (err) {
      setResult(null);
      setError(err.message);
    }
  };

  return (
    <div className="max-w-7xl mx-auto p-6 space-y-6">
      <h1 className="text-2xl font-bold">Insight Search UI</h1>

      {/* Filter dropdown */}
      <div className="flex gap-4 items-center">
        <select
          className="border border-gray-300 rounded px-3 py-2 w-full"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        >
          <option value="">-- Select an Insight to Filter --</option>
          {insightOptions.map((insight, idx) => (
            <option key={idx} value={insight}>{insight}</option>
          ))}
        </select>

        <button
          onClick={filterByInsight}
          className="bg-indigo-600 text-white px-4 py-2 rounded hover:bg-indigo-700"
        >
          Filter
        </button>
      </div>

      {error && <p className="text-red-500">❌ {error}</p>}

      {/* Unified table display */}
      {result && (
        <div className="overflow-x-auto bg-white border rounded shadow p-6">
          <h2 className="text-xl font-semibold mb-4">{result.insightName}</h2>
          <table className="w-full text-sm border border-gray-300">
            <thead className="bg-gray-100 text-left">
              <tr>
                <th className="border px-3 py-2">Insight Name</th>
                <th className="border px-3 py-2">Calculation</th>
                <th className="border px-3 py-2">Used In Products</th>
                <th className="border px-3 py-2">Data Point</th>
                <th className="border px-3 py-2">Source</th>
                <th className="border px-3 py-2">System</th>
                <th className="border px-3 py-2">Table</th>
                <th className="border px-3 py-2">Field</th>
                <th className="border px-3 py-2">Data Type</th>
              </tr>
            </thead>
            <tbody>
              {result.dataPoints?.map((dp, dpIndex) => (
                Array.isArray(dp.sourceMapping) && dp.sourceMapping.length > 0 ? (
                  dp.sourceMapping.map((m, mIndex) => (
                    <tr key={`${dpIndex}-${mIndex}`} className="even:bg-gray-50">
                      <td className="border px-3 py-2">{result.insightName}</td>
                      <td className="border px-3 py-2">{result.calculation}</td>
                      <td className="border px-3 py-2">{result.productsUsedIn.join(', ')}</td>
                      <td className="border px-3 py-2">{dp.name}</td>
                      <td className="border px-3 py-2">{m.sourceName}</td>
                      <td className="border px-3 py-2">{m.sourceSystem}</td>
                      <td className="border px-3 py-2">{m.table}</td>
                      <td className="border px-3 py-2">{m.field}</td>
                      <td className="border px-3 py-2">{m.dataType}</td>
                    </tr>
                  ))
                ) : (
                  <tr key={`missing-${dpIndex}`} className="bg-red-50">
                    <td className="border px-3 py-2">{result.insightName}</td>
                    <td className="border px-3 py-2">{result.calculation}</td>
                    <td className="border px-3 py-2">{result.productsUsedIn.join(', ')}</td>
                    <td className="border px-3 py-2">{dp.name}</td>
                    <td className="border px-3 py-2 text-red-600" colSpan={5}>No source mapping</td>
                  </tr>
                )
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
